def _run(cmd: list[str], *, cwd: Path) -> None:
    print("+", " ".join(cmd), flush=True)
    subprocess.run(cmd, cwd=cwd, check=True)

def _run_module(module: str, *, data_dir: Path) -> None:
    _run(
        [sys.executable, "-m", module, "--data-dir", str(data_dir)],
        cwd=BACKEND_DIR,
    )

